import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma"; // 共通のPrismaインスタンスを使用

export async function GET() {
  try {
    // 全ての利用者を、新しい順に取得
    const users = await prisma.user.findMany({
      select: {
        id: true,
        name: true,
        email: true,
        gender: true,
        symptom: true, // どんな悩みを持っているか
        medicalHistory: true, // 既往歴
        createdAt: true,
        // ★ password は絶対に含めない！
      },
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json(users);
  } catch (error: any) {
    console.error("ユーザー一覧取得エラー:", error);
    return NextResponse.json(
      { message: "データ取得に失敗しました", detail: error.message }, 
      { status: 500 }
    );
  }
}

//管理画面やセラピストが「どんな患者さんが登録しているか」を確認するための、ユーザー一覧取得API

//セキュリティ・バイ・デザイン:
//「一覧取得において、パスワードなどの機密情報を select 句で除外するのは鉄則です。利用者のプライバシーを守る設計を徹底しています」という、エンジニアとしての信頼性。

//マーケティング視点:
